import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire input as a single string
        String input = new String(System.in.readAllBytes(), StandardCharsets.UTF_8);
        // Replace literal "\n" sequences and actual newlines with spaces
        input = input.replace("\\n", " ");
        input = input.replace("\n", " ");
        input = input.replace("\r", " ");
        // Split by any whitespace
        String[] tokens = input.trim().split("\\s+");
        int idx = 0;
        int T = Integer.parseInt(tokens[idx++]);
        int youScore = 0, compScore = 0;
        StringBuilder out = new StringBuilder();
        for (int round = 1; round <= T; round++) {
            String you = tokens[idx++];
            String comp = tokens[idx++];
            int res = compare(you, comp);
            if (res == 1) {
                youScore++;
                out.append("Round ").append(round).append(": You\n");
            } else if (res == -1) {
                compScore++;
                out.append("Round ").append(round).append(": Computer\n");
            } else {
                out.append("Round ").append(round).append(": Tie\n");
            }
        }
        if (youScore > compScore) {
            out.append("You won the overall match");
        } else if (youScore < compScore) {
            out.append("Computer won the overall match");
        } else {
            out.append("Tie");
        }
        System.out.print(out.toString());
    }

    private static int compare(String a, String b) {
        if (a.equals(b)) return 0;
        switch (a) {
            case "Rock":
                if (b.equals("Scissors")) return 1;
                if (b.equals("Paper") || b.equals("Water")) return -1;
                break;
            case "Paper":
                if (b.equals("Rock")) return 1;
                if (b.equals("Scissors") || b.equals("Water")) return -1;
                break;
            case "Scissors":
                if (b.equals("Paper") || b.equals("Water")) return 1;
                if (b.equals("Rock")) return -1;
                break;
            case "Water":
                if (b.equals("Paper") || b.equals("Scissors")) return 1;
                if (b.equals("Rock")) return -1;
                break;
        }
        return 0; // should never reach here
    }
}

